import React, { useState } from 'react';
import { AsyncStorage } from 'react-native';

const LocalDataManager = () => {
  const [data, setData] = useState({});

  const fetchUserPreferences = async () => {
    const userPreferences = await AsyncStorage.getItem('user_preferences');
    if (userPreferences) {
      setData(JSON.parse(userPreferences));
    } else {
      setData({});
    }
  };

  const fetchSessionData = async () => {
    const sessionData = await AsyncStorage.getItem('session_data');
    if (sessionData) {
      setData(JSON.parse(sessionData));
    } else {
      setData({});
    }
  };

  const fetchOfflineContent = async () => {
    const offlineContent = await AsyncStorage.getItem('offline_content');
    if (offlineContent) {
      setData(JSON.parse(offlineContent));
    } else {
      setData({});
    }
  };

  return {
    fetchUserPreferences,
    fetchSessionData,
    fetchOfflineContent
  };
};

export default LocalDataManager;